<?php
declare(strict_types=1);
if(PHP_SAPI!=='cli'){http_response_code(404);exit('Not found.');}
require_once dirname(__DIR__).'/api/db.php';
$date=$argv[1]??date('Y-m-d',strtotime('-1 day'));if(!preg_match('/^\d{4}-\d{2}-\d{2}$/',$date)){fwrite(STDERR,"Usage: php scripts/aggregate_stage4e_distribution.php YYYY-MM-DD\n");exit(1);} $pdo=mg_db();
try{$pdo->beginTransaction();$pdo->prepare('DELETE FROM distribution_daily_metrics WHERE metric_date=?')->execute([$date]);$pdo->prepare("INSERT INTO distribution_daily_metrics (metric_date,merchant_user_id,program_id,source_type,received_events,duplicate_events,rejected_events,allocations,items_queued,items_issued,issued_value_cents,unique_recipients,updated_at) SELECT ?,dp.merchant_user_id,dp.id,COALESCE(dse.source_type,'manual'),COUNT(DISTINCT dse.id),SUM(dse.status='duplicate'),SUM(dse.status='rejected'),COUNT(DISTINCT da.id),COALESCE(SUM(da.quantity),0),COALESCE(SUM(CASE WHEN dij.status='issued' THEN 1 ELSE 0 END),0),COALESCE(SUM(CASE WHEN dij.status='issued' THEN da.unit_value_cents ELSE 0 END),0),COUNT(DISTINCT da.recipient_id),NOW() FROM distribution_programs dp LEFT JOIN distribution_source_events dse ON dse.program_id=dp.id AND DATE(dse.received_at)=? LEFT JOIN distribution_allocations da ON da.program_id=dp.id AND DATE(da.created_at)=? LEFT JOIN distribution_issuance_jobs dij ON dij.allocation_id=da.id GROUP BY dp.id,COALESCE(dse.source_type,'manual')")->execute([$date,$date,$date]);$pdo->commit();echo "Aggregated distribution metrics for {$date}.\n";exit(0);}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();fwrite(STDERR,'FAILED: '.$e->getMessage()."\n");exit(1);}
